class Solution {
public:
    int minimizedStringLength(string s) {
        int n = s.size();
        vector<int> last(n, -1);
        for (int i = n - 1; i >= 0; --i) {
            last[s[i] - 'a'] = i;
        }
        int res = n;
        for (int i = 0; i < n; ++i) {
            int j = last[s[i] - 'a'];
            if (j != -1) {
                res -= 2;
                last[s[i] - 'a'] = -1;
                if (j > i) {
                    last[s[j] - 'a'] = -1;
                }
            }
        }
        return res;
    }
};
```

